const STATUS_CONFIG = {
    pending: { color: "bg-yellow-400", label: "Pending" },
    approved: { color: "bg-green-500", label: "Completed" },
    canceled: { color: "bg-red-500", label: "Canceled" },
};

interface BookingTableProps {
    data: IBooking[];
    onUpdateStatus: (id: string, status: "approved" | "canceled") => void;
    updatingId: string | null;
    hidePagination?: boolean;
}

export function BookingTable({ data, onUpdateStatus, updatingId, hidePagination = false }: BookingTableProps) {
    const {
        filter, setFilter,
        eventTypeFilter, setEventTypeFilter,
        sortBy, setSortBy,
        sortOrder, setSortOrder,
        page, setPage,
        totalPages, totalItems,
        events
    } = useAdminContext();

    const [viewedBooking, setViewedBooking] = React.useState<IBooking | null>(null);

    // Helper to get event name (handles dynamic events)
    const getEventName = (type: string) => {
        const event = events.find(e => e.name === type || e._id === type);
        return event ? event.name : (EVENT_TYPE_LABELS[type as EventType] || type);
    };

    // Export Logic
    const exportToExcel = () => {
        const worksheet = XLSX.utils.json_to_sheet(data.map(b => ({
            ID: b._id,
            Event: getEventName(b.eventType),
            Client: b.clientName,
            Email: b.clientEmail,
            Phone: b.clientPhone,
            Date: format(new Date(b.eventDate), "PPP"),
            Time: b.eventTime,
            Status: b.status.toUpperCase(),
        })));
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "Bookings");
        XLSX.writeFile(workbook, `Bookings_Export_${format(new Date(), "yyyy-MM-dd")}.xlsx`);
    };

    const exportToPDF = () => {
        const doc = new jsPDF();
        const tableColumn = ["Event", "Client", "Date", "Status"];
        const tableRows = data.map(b => [
            getEventName(b.eventType),
            b.clientName,
            format(new Date(b.eventDate), "MMM dd, yyyy"),
            b.status.toUpperCase()
        ]);

        autoTable(doc, {
            head: [tableColumn],
            body: tableRows,
            startY: 20,
            theme: 'grid',
            headStyles: { fillColor: [30, 41, 59] }
        });
        doc.text("Bookings Registry Report", 14, 15);
        doc.save(`Bookings_Report_${format(new Date(), "yyyy-MM-dd")}.pdf`);
    };

    const handleSort = (key: string) => {
        if (sortBy === key) {
            setSortOrder(sortOrder === "asc" ? "desc" : "asc");
        } else {
            setSortBy(key);
            setSortOrder("desc");
        }
    };

    const columns: ColumnDef<IBooking>[] = [
        {
            accessorKey: "_id",
            header: "#",
            cell: ({ row }) => <span className="text-slate-900 text-[10px] font-medium">{(page - 1) * 10 + row.index + 1}</span>,
        },
        {
            accessorKey: "eventType",
            header: () => (
                <button
                    onClick={() => handleSort("eventType")}
                    className="flex items-center gap-2 hover:text-slate-900 transition-colors uppercase"
                >
                    Event
                    {sortBy === "eventType" ? (
                        sortOrder === "asc" ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                    ) : (
                        <ArrowUpDown className="h-3 w-3 text-slate-900" />
                    )}
                </button>
            ),
            cell: ({ row }) => (
                <span className="font-medium text-slate-800 text-sm">
                    {getEventName(row.original.eventType)}
                </span>
            ),
        },
        {
            accessorKey: "clientName",
            header: "Assigned To",
            cell: ({ row }) => (
                <div className="flex items-center gap-3">
                    <div className="h-7 w-7 rounded-sm bg-slate-100 flex items-center justify-center text-slate-400">
                        <User className="h-4 w-4" />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-sm font-medium text-slate-900 leading-none">{row.original.clientName}</span>
                        <span className="text-[10px] text-slate-900 font-medium uppercase mt-0.5">{row.original.clientEmail}</span>
                    </div>
                </div>
            ),
        },
        {
            accessorKey: "status",
            header: () => (
                <button
                    onClick={() => handleSort("status")}
                    className="flex items-center gap-2 hover:text-slate-900 transition-colors uppercase"
                >
                    Status
                    {sortBy === "status" ? (
                        sortOrder === "asc" ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                    ) : (
                        <ArrowUpDown className="h-3 w-3 text-slate-300" />
                    )}
                </button>
            ),
            cell: ({ row }) => {
                const config = STATUS_CONFIG[row.original.status as keyof typeof STATUS_CONFIG] || { color: "bg-slate-300", label: row.original.status };
                return (
                    <div className="flex items-center gap-2">
                        <div className={`h-1.5 w-1.5 rounded-full ${config.color}`} />
                        <span className="text-[10px] font-medium text-slate-700 uppercase tracking-tighter">{config.label}</span>
                    </div>
                );
            },
        },
        {
            accessorKey: "eventDate",
            header: () => (
                <button
                    onClick={() => handleSort("eventDate")}
                    className="flex items-center gap-2 hover:text-slate-900 transition-colors uppercase"
                >
                    Due Date
                    {sortBy === "eventDate" ? (
                        sortOrder === "asc" ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                    ) : (
                        <ArrowUpDown className="h-3 w-3 text-slate-300" />
                    )}
                </button>
            ),
            cell: ({ row }) => (
                <span className="text-slate-900 font-medium text-[11px] uppercase tracking-tighter">
                    {format(new Date(row.original.eventDate), "dd MMM yyyy")}
                </span>
            ),
        },
        {
            id: "actions",
            header: "Action",
            cell: ({ row }) => {
                const booking = row.original;
                const isPending = booking.status === "pending";

                return (
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button
                                variant="ghost"
                                className="h-8 w-8 p-0 text-slate-900 hover:text-slate-900"
                                data-test-id="admin-btn-more-actions"
                            >
                                <MoreHorizontal className="h-4 w-4" />
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="bg-white border border-slate-200 shadow-xl w-48">
                            <DropdownMenuLabel className="text-[10px] font-medium text-slate-400 uppercase p-3">Row Control</DropdownMenuLabel>

                            <DropdownMenuItem
                                onClick={() => navigator.clipboard.writeText(booking._id)}
                                className="gap-2 cursor-pointer"
                            >
                                <Copy className="h-4 w-4 text-slate-400" />
                                <span className="text-sm font-medium text-slate-600">Copy Master ID</span>
                            </DropdownMenuItem>

                            <DropdownMenuItem
                                onClick={() => setViewedBooking(booking)}
                                className="gap-2 cursor-pointer"
                            >
                                <Eye className="h-4 w-4 text-slate-900" />
                                <span className="text-sm font-medium text-slate-900">View Detailed Profile</span>
                            </DropdownMenuItem>

                            {isPending && (
                                <>
                                    <DropdownMenuSeparator />
                                    <DropdownMenuItem
                                        onClick={() => onUpdateStatus(booking._id, "approved")}
                                        disabled={updatingId === booking._id}
                                        className="gap-2 cursor-pointer text-emerald-600 focus:text-emerald-700 focus:bg-emerald-50"
                                        data-test-id={`admin-btn-approve-${booking._id}`}
                                    >
                                        <CircleCheck className="h-4 w-4" />
                                        <span className="text-sm font-medium">Approve Request</span>
                                    </DropdownMenuItem>
                                    <DropdownMenuItem
                                        onClick={() => onUpdateStatus(booking._id, "canceled")}
                                        disabled={updatingId === booking._id}
                                        className="gap-2 cursor-pointer text-red-600 focus:text-red-700 focus:bg-red-50"
                                        data-test-id={`admin-btn-cancel-${booking._id}`}
                                    >
                                        <CircleX className="h-4 w-4" />
                                        <span className="text-sm font-medium">Decline Request</span>
                                    </DropdownMenuItem>
                                </>
                            )}
                        </DropdownMenuContent>
                    </DropdownMenu>
                );
            },
        },
    ];

    const table = useReactTable({
        data,
        columns,
        getCoreRowModel: getCoreRowModel(),
    });

    return (
        <div className="space-y-4">
            {/* Table Controls (Filtering & Export) */}
            {!hidePagination && (
                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex flex-wrap items-center gap-3">
                        <div className="flex items-center gap-2 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100">
                            <Filter className="h-3.5 w-3.5 text-slate-900" />
                            <span className="text-xs font-medium text-slate-900 uppercase tracking-tighter">FILTERS</span>
                        </div>

                        <Select value={filter} onValueChange={setFilter}>
                            <SelectTrigger className="w-[130px] h-9 text-xs font-medium border-slate-200 focus:ring-0 focus:border-slate-400 transition-all uppercase tracking-tighter" data-test-id="admin-filter-status">
                                <SelectValue placeholder="Status" />
                            </SelectTrigger>
                            <SelectContent className="border-none shadow-2xl bg-white">
                                <SelectItem value="all" className="text-xs font-medium uppercase tracking-tighter" data-test-id="admin-filter-status-all">All Status</SelectItem>
                                <SelectItem value="pending" className="text-xs font-medium uppercase tracking-tighter" data-test-id="admin-filter-status-pending">Pending</SelectItem>
                                <SelectItem value="approved" className="text-xs font-medium uppercase tracking-tighter" data-test-id="admin-filter-status-approved">Completed</SelectItem>
                                <SelectItem value="canceled" className="text-xs font-medium uppercase tracking-tighter" data-test-id="admin-filter-status-canceled">Canceled</SelectItem>
                            </SelectContent>
                        </Select>

                        <Select value={eventTypeFilter} onValueChange={setEventTypeFilter}>
                            <SelectTrigger className="w-[150px] h-9 text-xs font-medium border-slate-200 focus:ring-0 focus:border-slate-400 transition-all uppercase tracking-tighter" data-test-id="admin-filter-event">
                                <SelectValue placeholder="Event Type" />
                            </SelectTrigger>
                            <SelectContent className="border-none shadow-2xl bg-white">
                                <SelectItem value="all" className="text-xs font-medium uppercase tracking-tighter" data-test-id="admin-filter-event-all">All Events</SelectItem>
                                {events.map((e) => (
                                    <SelectItem key={e._id} value={e.name} className="text-xs font-medium uppercase tracking-tighter" data-test-id={`admin-filter-event-${e.name}`}>
                                        {e.name}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="flex items-center gap-2">
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={exportToExcel}
                            className="h-9 gap-2 text-[10px] font-medium uppercase tracking-tighter text-slate-900 border-slate-200 hover:bg-emerald-50 hover:text-emerald-700 transition-all"
                            data-test-id="admin-btn-export-excel"
                        >
                            <FileDown className="h-3.5 w-3.5 text-slate-900" />
                            Export Excel
                        </Button>
                        <Button
                            variant="default"
                            size="sm"
                            onClick={exportToPDF}
                            className="h-9 gap-2 text-[10px] font-medium uppercase tracking-tighter bg-primary text-white border-none hover:bg-primary/90 transition-all shadow-none"
                            data-test-id="admin-btn-export-pdf"
                        >
                            <FileDown className="h-3.5 w-3.5 text-white" />
                            Export PDF
                        </Button>
                    </div>
                </div>
            )}

            <div className="w-full bg-white rounded-xl border border-slate-200 shadow-none overflow-hidden">
                <Table>
                    <TableHeader className="bg-slate-50/50">
                        {table.getHeaderGroups().map((headerGroup) => (
                            <TableRow key={headerGroup.id} className="hover:bg-transparent border-b border-slate-200">
                                {headerGroup.headers.map((header) => (
                                    <TableHead key={header.id} className="h-12 text-[11px] font-medium text-slate-900 uppercase tracking-widest px-6 whitespace-nowrap">
                                        {header.isPlaceholder
                                            ? null
                                            : flexRender(
                                                header.column.columnDef.header,
                                                header.getContext()
                                            )}
                                    </TableHead>
                                ))}
                            </TableRow>
                        ))}
                    </TableHeader>
                    <TableBody>
                        {table.getRowModel().rows?.length ? (
                            table.getRowModel().rows.map((row) => (
                                <TableRow
                                    key={row.id}
                                    className="border-b border-slate-100 last:border-0 hover:bg-slate-50/50 transition-all"
                                >
                                    {row.getVisibleCells().map((cell) => (
                                        <TableCell key={cell.id} className="px-6 py-4">
                                            {flexRender(cell.column.columnDef.cell, cell.getContext())}
                                        </TableCell>
                                    ))}
                                </TableRow>
                            ))
                        ) : (
                            <TableRow>
                                <TableCell colSpan={6} className="h-40 text-center text-slate-900 font-medium text-sm uppercase tracking-tighter">
                                    No records matching strict filters found in registry
                                </TableCell>
                            </TableRow>
                        )}
                    </TableBody>
                </Table>

                {/* Pagination */}
                {!hidePagination && (
                    <div className="flex items-center justify-between px-6 py-4 bg-slate-50/50 border-t border-slate-200">
                        <div className="text-[10px] text-slate-900 font-medium uppercase tracking-widest">
                            Found <span className="text-slate-900 font-medium">{totalItems}</span> total entries in database
                        </div>
                        <div className="flex items-center gap-2">
                            <Button
                                variant="outline"
                                size="sm"
                                className="h-8 px-3 rounded-md border-slate-200 text-slate-500 text-[10px] font-medium uppercase tracking-widest disabled:opacity-30"
                                onClick={() => setPage(page - 1)}
                                disabled={page === 1}
                                data-test-id="admin-btn-pagination-prev"
                            >
                                Previous
                            </Button>
                            <div className="flex items-center gap-1.5">
                                <div className="h-8 w-8 rounded-md bg-slate-900 text-white flex items-center justify-center text-xs font-medium">
                                    {page}
                                </div>
                                <span className="text-[10px] font-medium text-slate-900 uppercase italic">of {totalPages}</span>
                            </div>
                            <Button
                                variant="outline"
                                size="sm"
                                className="h-8 px-3 rounded-md border-slate-200 text-slate-900 text-[10px] font-medium uppercase tracking-widest disabled:opacity-30"
                                onClick={() => setPage(page + 1)}
                                disabled={page >= totalPages}
                                data-test-id="admin-btn-pagination-next"
                            >
                                Next
                            </Button>
                        </div>
                    </div>
                )}
            </div>

            <BookingViewModal
                booking={viewedBooking}
                isOpen={!!viewedBooking}
                onClose={() => setViewedBooking(null)}
                onUpdateStatus={onUpdateStatus}
                updatingId={updatingId}
            />
        </div>
    );
}

"use client";

import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    DialogFooter,
    DialogClose,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { format } from "date-fns";
import type { IBooking, EventType } from "@/types/booking";
import { EVENT_TYPE_LABELS } from "@/types/booking";
import {
    Copy,
    Mail,
    Phone,
    Calendar,
    Clock,
    User,
    ClipboardList,
    BadgeCheck,
    Hash
} from "lucide-react";
import { formatPHP } from "@/lib/format";
import { useAdminContext } from "../AdminProvider";

interface BookingViewModalProps {
    booking: IBooking | null;
    isOpen: boolean;
    onClose: () => void;
    onUpdateStatus: (id: string, status: "approved" | "canceled") => void;
    updatingId: string | null;
}

const STATUS_CONFIG = {
    pending: { color: "bg-yellow-400", text: "text-amber-700", bg: "bg-amber-50", label: "Pending Review" },
    approved: { color: "bg-green-500", text: "text-emerald-700", bg: "bg-emerald-50", label: "Completed" },
    canceled: { color: "bg-red-500", text: "text-rose-700", bg: "bg-rose-50", label: "Canceled" },
};

export function BookingViewModal({ booking, isOpen, onClose, onUpdateStatus, updatingId }: BookingViewModalProps) {
    const { events } = useAdminContext();
    if (!booking) return null;

    const status = STATUS_CONFIG[booking.status as keyof typeof STATUS_CONFIG] || {
        color: "bg-slate-300",
        text: "text-slate-700",
        bg: "bg-slate-50",
        label: booking.status
    };

    // Helper to get event name (handles dynamic events)
    const getEventName = (type: string) => {
        const event = events.find(e => e.name === type || e._id === type);
        return event ? event.name : (EVENT_TYPE_LABELS[type as EventType] || type);
    };

    const DataRow = ({ label, value, icon: Icon }: { label: string; value: string | React.ReactNode; icon: any }) => (
        <div className="flex items-center justify-between py-3 border-b border-slate-100 last:border-0 hover:bg-slate-50/50 transition-colors px-1">
            <div className="flex items-center gap-3">
                <div className="h-8 w-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400">
                    <Icon className="h-4 w-4" />
                </div>
                <span className="text-xs font-medium text-slate-500 uppercase tracking-wider">{label}</span>
            </div>
            <div className="text-sm font-medium text-slate-900">{value}</div>
        </div>
    );

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
            <DialogContent
                className="sm:max-w-[600px] p-0 overflow-hidden bg-white border-none shadow-2xl rounded-2xl"
                data-test-id="admin-modal-booking-details"
            >
                <div className="bg-slate-900 p-8 text-white relative">
                    <div className="absolute top-8 right-8">
                        <div className={`px-4 py-1.5 rounded-full ${status.bg} ${status.text} text-[10px] font-medium uppercase tracking-widest flex items-center gap-2 border border-white/10`}>
                            <div className={`h-1.5 w-1.5 rounded-full ${status.color}`} />
                            {status.label}
                        </div>
                    </div>

                    <div className="space-y-1">
                        <div className="flex items-center gap-2 text-blue-400 text-[10px] font-medium uppercase tracking-[0.2em] mb-2">
                            <BadgeCheck className="h-4 w-4" />
                            Registry Entry
                        </div>
                        <DialogTitle className="text-3xl font-bold tracking-tight leading-none">
                            {getEventName(booking.eventType)}
                        </DialogTitle>
                        <DialogDescription className="text-slate-400 text-xs font-medium flex items-center gap-2 mt-2">
                            <Hash className="h-3 w-3" />
                            Reference ID: <span className="text-slate-300 select-all font-mono">{booking._id}</span>
                            <button
                                onClick={() => navigator.clipboard.writeText(booking._id)}
                                className="hover:text-white transition-colors p-1"
                                data-test-id="admin-btn-copy-id"
                            >
                                <Copy className="h-3 w-3" />
                            </button>
                        </DialogDescription>
                    </div>
                </div>

                <div className="p-8 space-y-8">
                    {/* Customer Section */}
                    <div className="space-y-4">
                        <h3 className="text-[10px] font-medium text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <User className="h-3 w-3" />
                            Customer Identification
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                                <p className="text-[10px] font-medium text-slate-400 uppercase mb-1">Full Name</p>
                                <p className="text-sm font-medium text-slate-900 uppercase">{booking.clientName}</p>
                            </div>
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 overflow-hidden">
                                <p className="text-[10px] font-medium text-slate-400 uppercase mb-1">Contact Email</p>
                                <a href={`mailto:${booking.clientEmail}`} className="text-sm font-medium text-blue-600 truncate block hover:underline">
                                    {booking.clientEmail}
                                </a>
                            </div>
                        </div>
                    </div>

                    {/* Schedule Section */}
                    <div className="space-y-2">
                        <h3 className="text-[10px] font-medium text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-4">
                            <Calendar className="h-3 w-3" />
                            Event Specification
                        </h3>
                        <div className="rounded-xl border border-slate-100 overflow-hidden px-4">
                            <DataRow
                                label="Scheduled Date"
                                value={format(new Date(booking.eventDate), "MMMM dd, yyyy")}
                                icon={Calendar}
                            />
                            <DataRow
                                label="Time Window"
                                value={booking.eventTime}
                                icon={Clock}
                            />
                            <DataRow
                                label="Project Value"
                                value={formatPHP(1500)} // Placeholder standardized rate
                                icon={ClipboardList}
                            />
                        </div>
                    </div>

                    {/* Add-ons/Notes */}
                    {(booking.addOns?.length || booking.notes) && (
                        <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-4">
                            {booking.addOns?.length && (
                                <div className="space-y-2">
                                    <p className="text-[10px] font-medium text-slate-400 uppercase">Selected Add-ons</p>
                                    <div className="flex flex-wrap gap-2">
                                        {booking.addOns.map(add => (
                                            <span key={add} className="px-2 py-0.5 bg-white border border-slate-200 rounded text-[9px] font-medium text-slate-600 uppercase">
                                                {add}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {booking.notes && (
                                <div className="space-y-2">
                                    <p className="text-[10px] font-medium text-slate-400 uppercase tracking-tighter">Internal Specification Notes</p>
                                    <p className="text-xs text-slate-600 leading-relaxed font-medium italic select-all">
                                        &ldquo;{booking.notes}&rdquo;
                                    </p>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <DialogFooter className="px-8 py-6 bg-slate-50 border-t border-slate-100 flex items-center sm:justify-between">
                    <span className="text-[9px] font-medium text-slate-400 uppercase tracking-widest">
                        Created: {format(new Date(booking.createdAt), "MM/dd/yy p")}
                    </span>
                    <div className="flex gap-2">
                        {booking.status === "pending" ? (
                            <>
                                <Button
                                    className="h-10 px-6 font-normal bg-red-600 text-white"
                                    onClick={() => onUpdateStatus(booking._id, "canceled")}
                                    disabled={updatingId === booking._id}
                                    data-test-id="admin-btn-modal-cancel"
                                >
                                    Cancel
                                </Button>
                                <Button
                                    className="h-10 px-8 font-normal bg-slate-900 text-white"
                                    onClick={() => onUpdateStatus(booking._id, "approved")}
                                    disabled={updatingId === booking._id}
                                    data-test-id="admin-btn-modal-approve"
                                >
                                    Approve
                                </Button>
                            </>
                        ) : (
                            <DialogClose asChild>
                                <Button
                                    variant="outline"
                                    className="h-10 px-6 font-normal text-slate-600 border-slate-200"
                                    data-test-id="admin-btn-modal-close"
                                >
                                    Close
                                </Button>
                            </DialogClose>
                        )}
                    </div>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React, { useState } from "react";
import { useEvents } from "../sub-helpers/useEvents";
import type { IEvent } from "@/lib/models/Event";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
    DialogDescription
} from "@/components/ui/dialog";
import { formatPHP } from "@/lib/format";
import {
    PlusCircle,
    Search,
    Edit2,
    Trash2,
    Power,
    Eye,
    Settings2,
    CircleDollarSign,
    Clock,
    MoreHorizontal,
    Plus,
    X
} from "lucide-react";
import { Badge } from "@/components/ui/badge";

export function EventManager() {
    const { events, isLoading, createEvent, updateEvent, toggleEventStatus, deleteEvent, isSubmitting, updatingId } = useEvents();
    const [searchTerm, setSearchTerm] = useState("");
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [isViewOpen, setIsViewOpen] = useState(false);
    const [editingEvent, setEditingEvent] = useState<IEvent | null>(null);
    const [viewedEvent, setViewedEvent] = useState<IEvent | null>(null);

    // Form State
    const [formData, setFormData] = useState({
        name: "",
        description: "",
        basePrice: "" as number | string,
        duration: "",
        process: "",
        addons: [] as { name: string, price: number | string }[]
    });

    const filteredEvents = events.filter(e => e.name.toLowerCase().includes(searchTerm.toLowerCase()));

    const handleOpenForm = (event?: IEvent) => {
        if (event) {
            setEditingEvent(event);
            setFormData({
                name: event.name,
                description: event.description || "",
                basePrice: event.basePrice,
                duration: event.duration || "",
                process: event.process || "",
                addons: event.addons || []
            });
        } else {
            setEditingEvent(null);
            setFormData({
                name: "",
                description: "",
                basePrice: "",
                duration: "",
                process: "",
                addons: []
            });
        }
        setIsFormOpen(true);
    };

    const handleViewEvent = (event: IEvent) => {
        setViewedEvent(event);
        setIsViewOpen(true);
    };

    const handleAddAddon = () => {
        setFormData({
            ...formData,
            addons: [...formData.addons, { name: "", price: "" }]
        });
    };

    const handleRemoveAddon = (index: number) => {
        setFormData({
            ...formData,
            addons: formData.addons.filter((_, i) => i !== index)
        });
    };

    const handleAddonUpdate = (index: number, field: 'name' | 'price', value: string | number) => {
        const newAddons = [...formData.addons];
        newAddons[index] = { ...newAddons[index], [field]: value };
        setFormData({ ...formData, addons: newAddons });
    };

    const handleSave = (e: React.FormEvent) => {
        e.preventDefault();
        const payload = { ...formData, basePrice: Number(formData.basePrice) };

        if (editingEvent) {
            updateEvent(editingEvent._id as unknown as string, payload, () => setIsFormOpen(false));
        } else {
            createEvent(payload, () => setIsFormOpen(false));
        }
    };

    if (isLoading) return <div className="p-8 text-center text-slate-900 font-medium uppercase tracking-widest">Synchronizing Event Engine...</div>;

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <div className="relative w-full sm:w-96">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-900" />
                    <Input
                        placeholder="Search configurations..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-10 h-10 border-slate-900 focus:ring-blue-500 font-medium text-sm uppercase tracking-tighter"
                        data-test-id="admin-input-event-search"
                    />
                </div>
                <Button
                    onClick={() => handleOpenForm()}
                    className="h-10 px-6 font-bold bg-slate-900 text-white w-full sm:w-auto hover:bg-slate-800 transition-all shadow-md active:scale-95"
                    data-test-id="admin-btn-event-create"
                >
                    <PlusCircle className="mr-2 h-4 w-4" />
                    New Event Type
                </Button>
            </div>

            <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-md">
                <Table>
                    <TableHeader className="bg-slate-50/50">
                        <TableRow className="border-b border-slate-200">
                            <TableHead className="font-medium text-slate-900 text-[11px] uppercase tracking-widest px-6 h-12 text-center w-16">#</TableHead>
                            <TableHead className="font-medium text-slate-900 text-[11px] uppercase tracking-widest px-6 h-12">Event Configuration</TableHead>
                            <TableHead className="font-medium text-slate-900 text-[11px] uppercase tracking-widest px-6 h-12">Value Structure</TableHead>
                            <TableHead className="font-medium text-slate-900 text-[11px] uppercase tracking-widest px-6 h-12">Availability</TableHead>
                            <TableHead className="text-right font-medium text-slate-900 text-[11px] uppercase tracking-widest px-6 h-12">Action Control</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredEvents.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={5} className="text-center py-12 text-slate-900 font-medium uppercase tracking-tighter">No event configurations detected in the registry.</TableCell>
                            </TableRow>
                        ) : filteredEvents.map((event, index) => (
                            <TableRow key={event._id as unknown as string} className="border-b border-slate-100 last:border-0 hover:bg-slate-50/50 transition-colors">
                                <TableCell className="px-6 py-4 text-center">
                                    <span className="text-[10px] font-medium text-slate-900">{index + 1}</span>
                                </TableCell>
                                <TableCell className="px-6 py-4">
                                    <div className="flex flex-col">
                                        <p className="font-medium text-slate-900 text-sm leading-tight">{event.name}</p>
                                        <p className="text-[11px] text-slate-900 font-medium mt-0.5 line-clamp-1 uppercase tracking-tighter">
                                            {event.description || "No description provided."}
                                        </p>
                                    </div>
                                </TableCell>
                                <TableCell className="px-6 py-4 outline-none">
                                    <div className="flex items-center gap-2">
                                        <CircleDollarSign className="h-3.5 w-3.5 text-emerald-500" />
                                        <span className="font-medium text-slate-700 text-sm">{formatPHP(event.basePrice)}</span>
                                    </div>
                                </TableCell>
                                <TableCell className="px-6 py-4">
                                    <Badge variant={event.isActive ? "secondary" : "outline"} className={`uppercase text-[9px] font-medium tracking-widest px-2 py-0.5 ${event.isActive ? 'bg-emerald-50 text-emerald-700 border-emerald-900' : 'text-slate-900 border-slate-900'}`}>
                                        {event.isActive ? 'Online' : 'Draft'}
                                    </Badge>
                                </TableCell>
                                <TableCell className="px-6 py-4 text-right">
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild>
                                            <Button
                                                variant="ghost"
                                                className="h-8 w-8 p-0 text-slate-900 hover:text-slate-900"
                                            >
                                                <MoreHorizontal className="h-4 w-4" />
                                            </Button>
                                        </DropdownMenuTrigger>
                                        <DropdownMenuContent align="end" className="bg-white border border-slate-200 shadow-xl w-48">
                                            <DropdownMenuLabel className="text-[10px] font-medium text-slate-900 uppercase p-3 tracking-widest">Event Control</DropdownMenuLabel>

                                            <DropdownMenuItem
                                                onClick={() => handleOpenForm(event)}
                                                disabled={updatingId === (event._id as unknown as string)}
                                                className="gap-2 cursor-pointer"
                                                data-test-id={`admin-btn-event-edit-${event.name}`}
                                            >
                                                <Edit2 className="h-4 w-4 text-slate-400" />
                                                <span className="text-sm font-medium text-slate-600">Edit Configuration</span>
                                            </DropdownMenuItem>

                                            <DropdownMenuItem
                                                onClick={() => handleViewEvent(event)}
                                                className="gap-2 cursor-pointer"
                                                data-test-id={`admin-btn-event-view-${event.name}`}
                                            >
                                                <Eye className="h-4 w-4 text-slate-400" />
                                                <span className="text-sm font-medium text-slate-600">View Detailed rules</span>
                                            </DropdownMenuItem>

                                            <DropdownMenuSeparator />

                                            <DropdownMenuItem
                                                onClick={() => toggleEventStatus(event._id as unknown as string, event.isActive)}
                                                disabled={updatingId === (event._id as unknown as string)}
                                                className="gap-2 cursor-pointer"
                                                data-test-id={`admin-btn-event-toggle-${event.name}`}
                                            >
                                                <Power className="h-4 w-4 text-slate-400" />
                                                <span className="text-sm font-medium text-slate-900">
                                                    {event.isActive ? "Deactivate Event" : "Activate Event"}
                                                </span>
                                            </DropdownMenuItem>

                                            <DropdownMenuItem
                                                onClick={() => deleteEvent(event._id as unknown as string)}
                                                disabled={updatingId === (event._id as unknown as string)}
                                                className="gap-2 cursor-pointer text-red-600 focus:text-red-700 focus:bg-red-50"
                                                data-test-id={`admin-btn-event-delete-${event.name}`}
                                            >
                                                <Trash2 className="h-4 w-4" />
                                                <span className="text-sm font-medium">Delete Permanent</span>
                                            </DropdownMenuItem>
                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                </TableCell>
                            </TableRow>
                        ))}
                    </TableBody>
                </Table>
            </div>

            {/* View Event Modal */}
            <Dialog open={isViewOpen} onOpenChange={setIsViewOpen}>
                <DialogContent className="sm:max-w-xl p-0 overflow-hidden bg-white border-none rounded-2xl shadow-2xl">
                    {viewedEvent && (
                        <>
                            <div className="bg-slate-900 p-8 text-white">
                                <Badge className="mb-4 bg-blue-500/20 text-blue-300 border-blue-500/30 font-medium uppercase tracking-tighter text-[10px]">Registry Profile</Badge>
                                <DialogTitle className="text-3xl font-bold tracking-tight">{viewedEvent.name}</DialogTitle>
                            </div>
                            <div className="p-8 space-y-6">
                                <div className="grid grid-cols-2 gap-8 font-medium">
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Pricing Structure</p>
                                        <p className="text-xl font-bold text-slate-900 leading-none">{formatPHP(viewedEvent.basePrice)}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Duration Profile</p>
                                        <p className="text-xl font-bold text-slate-900 leading-none">{viewedEvent.duration || "unspecified"}</p>
                                    </div>
                                </div>

                                <div className="space-y-4 pt-4 border-t border-slate-100">
                                    <div className="space-y-2">
                                        <p className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Description & Scope</p>
                                        <p className="text-sm text-slate-900 leading-relaxed font-medium uppercase tracking-tighter">
                                            {viewedEvent.description || "No internal description available."}
                                        </p>
                                    </div>

                                    {viewedEvent.process && (
                                        <div className="space-y-2">
                                            <p className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Internal Process</p>
                                            <p className="text-sm text-slate-900 leading-relaxed font-medium whitespace-pre-wrap uppercase tracking-tighter">
                                                {viewedEvent.process}
                                            </p>
                                        </div>
                                    )}

                                    {viewedEvent.addons && viewedEvent.addons.length > 0 && (
                                        <div className="space-y-2">
                                            <p className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Add-on Inventory</p>
                                            <div className="grid grid-cols-2 gap-2">
                                                {viewedEvent.addons.map((addon, i) => (
                                                    <div key={i} className="flex justify-between items-center p-2 bg-slate-50 rounded-lg border border-slate-100">
                                                        <span className="text-[11px] font-medium text-slate-700">{addon.name}</span>
                                                        <span className="text-[11px] font-bold text-blue-600">{formatPHP(addon.price)}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </div>

                                <DialogFooter className="pt-6">
                                    <Button
                                        onClick={() => setIsViewOpen(false)}
                                        className="w-full h-11 bg-slate-100 text-slate-900 font-medium uppercase tracking-tighter hover:bg-slate-200 border-none transition-all shadow-none"
                                    >
                                        Close Profile
                                    </Button>
                                </DialogFooter>
                            </div>
                        </>
                    )}
                </DialogContent>
            </Dialog>

            {/* Event Form Modal */}
            <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
                <DialogContent className="sm:max-w-2xl p-0 overflow-hidden bg-white rounded-xl shadow-2xl border-none h-[90vh] flex flex-col">
                    <div className="bg-slate-900 p-6 shrink-0">
                        <DialogTitle className="text-xl font-bold text-white tracking-tight">
                            {editingEvent ? "Update Event Configuration" : "Initialize New Event"}
                        </DialogTitle>
                        <DialogDescription className="text-slate-900 text-xs font-medium mt-1 uppercase tracking-widest opacity-70">
                            {editingEvent ? "Modify existing event parameters." : "Define a new event profile for the registry."}
                        </DialogDescription>
                    </div>

                    <form onSubmit={handleSave} className="flex-1 overflow-y-auto p-6 space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <label className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Master Name</label>
                                    <Input
                                        value={formData.name}
                                        onChange={e => setFormData({ ...formData, name: e.target.value })}
                                        required
                                        className="h-10 font-bold"
                                        placeholder="e.g. Wedding Package"
                                    />
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Base Rate (PHP)</label>
                                        <Input
                                            type="number"
                                            value={formData.basePrice}
                                            onChange={e => setFormData({ ...formData, basePrice: e.target.value === "" ? "" : Number(e.target.value) })}
                                            required
                                            min="0"
                                            className="h-10 font-mono"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Duration Profile</label>
                                        <Input
                                            value={formData.duration}
                                            onChange={e => setFormData({ ...formData, duration: e.target.value })}
                                            className="h-10"
                                            placeholder="e.g. 8 Hours"
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Scope Description</label>
                                    <textarea
                                        value={formData.description}
                                        onChange={e => setFormData({ ...formData, description: e.target.value })}
                                        className="w-full h-24 p-3 rounded-md border border-slate-900 text-sm font-medium focus:ring-1 focus:ring-blue-500 focus:outline-none resize-none uppercase tracking-tighter"
                                        placeholder="Public-facing description..."
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Internal Process</label>
                                    <textarea
                                        value={formData.process}
                                        onChange={e => setFormData({ ...formData, process: e.target.value })}
                                        className="w-full h-32 p-3 rounded-md border border-slate-900 text-sm font-medium focus:ring-1 focus:ring-blue-500 focus:outline-none resize-none uppercase tracking-tighter"
                                        placeholder="Steps, procedures, etc..."
                                    />
                                </div>
                            </div>

                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <label className="text-[10px] font-medium text-slate-900 uppercase tracking-widest">Add-on Customization</label>
                                    <Button type="button" size="sm" variant="ghost" className="h-6 text-blue-600 font-bold text-[10px] hover:bg-blue-50" onClick={handleAddAddon}>
                                        <Plus className="h-3 w-3 mr-1" /> Add Option
                                    </Button>
                                </div>

                                <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                                    {formData.addons.length === 0 && (
                                        <div className="text-center py-8 bg-slate-50 rounded-lg border-2 border-dashed border-slate-200">
                                            <p className="text-[10px] font-medium text-slate-900 uppercase">No add-ons defined</p>
                                        </div>
                                    )}
                                    {formData.addons.map((addon, index) => (
                                        <div key={index} className="flex gap-2 items-start bg-white p-3 rounded-lg border border-slate-200 shadow-sm">
                                            <div className="flex-1 space-y-2">
                                                <Input
                                                    placeholder="Addon Name"
                                                    value={addon.name}
                                                    onChange={e => handleAddonUpdate(index, 'name', e.target.value)}
                                                    className="h-8 text-xs font-medium"
                                                />
                                                <Input
                                                    type="number"
                                                    placeholder="Price"
                                                    value={addon.price}
                                                    onChange={e => handleAddonUpdate(index, 'price', e.target.value === "" ? "" : Number(e.target.value))}
                                                    className="h-8 text-xs font-mono"
                                                />
                                            </div>
                                            <Button
                                                type="button"
                                                variant="ghost"
                                                size="icon"
                                                className="h-8 w-8 text-slate-900 hover:text-red-500"
                                                onClick={() => handleRemoveAddon(index)}
                                            >
                                                <X className="h-4 w-4" />
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </form>

                    <DialogFooter className="p-6 border-t border-slate-100 bg-slate-50 shrink-0">
                        <div className="flex justify-end gap-2 w-full">
                            <Button
                                type="button"
                                variant="outline"
                                onClick={() => setIsFormOpen(false)}
                                className="font-medium text-slate-900 border-slate-900 h-10 px-6 uppercase tracking-widest"
                                disabled={isSubmitting}
                                data-test-id="admin-btn-event-form-cancel"
                            >
                                Cancel
                            </Button>
                            <Button
                                onClick={handleSave}
                                className="font-bold bg-slate-900 text-white h-10 px-6"
                                disabled={isSubmitting}
                                data-test-id="admin-btn-event-form-commit"
                            >
                                {isSubmitting ? "Committing..." : "Commit Profile"}
                            </Button>
                        </div>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import React from "react";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { format } from "date-fns";
import { INotification } from "@/types/booking";
import { Bell, Calendar, CheckCircle2, Clock, ExternalLink } from "lucide-react";
import { useAdminContext } from "../AdminProvider";
import { Badge } from "@/components/ui/badge";

export function NotificationDetailsModal() {
    const { selectedNotification, setSelectedNotification, setCurrentView } = useAdminContext();

    if (!selectedNotification) return null;

    const handleAction = () => {
        if (selectedNotification.type === "new_booking" || selectedNotification.type === "status_change") {
            setCurrentView("BOOKINGS");
        }
        setSelectedNotification(null);
    };

    return (
        <Dialog open={!!selectedNotification} onOpenChange={(open) => !open && setSelectedNotification(null)}>
            <DialogContent className="sm:max-w-[500px] p-0 overflow-hidden bg-white border-none shadow-2xl rounded-2xl">
                <div className="bg-slate-900 p-8 text-white relative">
                    <div className="absolute top-0 right-0 p-4 opacity-10">
                        <Bell className="h-24 w-24 rotate-12" />
                    </div>

                    <div className="relative z-10 flex flex-col items-center text-center space-y-4">
                        <div className={`h-16 w-16 rounded-2xl flex items-center justify-center shadow-lg ${selectedNotification.type === "new_booking"
                                ? "bg-amber-500 text-white"
                                : "bg-blue-500 text-white"
                            }`}>
                            {selectedNotification.type === "new_booking" ? (
                                <Calendar className="h-8 w-8" />
                            ) : (
                                <CheckCircle2 className="h-8 w-8" />
                            )}
                        </div>

                        <div className="space-y-1">
                            <Badge className="bg-white/20 hover:bg-white/30 text-white border-none text-[10px] tracking-widest uppercase">
                                {selectedNotification.type.replace("_", " ")}
                            </Badge>
                            <DialogTitle className="text-xl font-bold tracking-tight text-white">
                                Notification Details
                            </DialogTitle>
                        </div>
                    </div>
                </div>

                <div className="p-8 space-y-6">
                    <div className="space-y-4">
                        <div className="flex items-start gap-4">
                            <div className="mt-1 h-8 w-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">
                                <Clock className="h-4 w-4" />
                            </div>
                            <div>
                                <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Received At</p>
                                <p className="text-sm font-medium text-slate-900">
                                    {format(new Date(selectedNotification.createdAt), "MMMM d, yyyy 'at' h:mm a")}
                                </p>
                            </div>
                        </div>

                        <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                            <p className="text-sm leading-relaxed text-slate-700 italic">
                                "{selectedNotification.message}"
                            </p>
                        </div>
                    </div>

                    <div className="flex flex-col gap-2 pt-2">
                        <Button
                            className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-6 h-auto rounded-xl shadow-lg transition-all active:scale-[0.98]"
                            onClick={handleAction}
                        >
                            <ExternalLink className="mr-2 h-4 w-4" />
                            Go to Related Record
                        </Button>
                        <Button
                            variant="ghost"
                            className="w-full text-slate-500 hover:text-slate-900 font-medium py-3"
                            onClick={() => setSelectedNotification(null)}
                        >
                            Dismiss
                        </Button>
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React from "react";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Button } from "@/components/ui/button";
import { Bell, Calendar, CheckCircle2, Inbox } from "lucide-react";
import { useAdminContext } from "../AdminProvider";
import { format } from "date-fns";
import { Badge } from "@/components/ui/badge";

export function NotificationDropdown() {
    const {
        notifications,
        unreadNotificationsCount,
        markNotificationRead,
        setSelectedNotification,
        setCurrentView
    } = useAdminContext();

    const recentNotifications = notifications.slice(0, 5);

    const handleNotificationClick = (notification: any) => {
        if (!notification.isRead) {
            markNotificationRead(notification._id);
        }
        setSelectedNotification(notification);
    };

    return (
        <DropdownMenu>
            <DropdownMenuTrigger asChild>
                <Button
                    variant="ghost"
                    size="icon"
                    className="text-slate-900 hover:text-blue-600 rounded-full relative transition-all duration-300 hover:bg-slate-100"
                >
                    <Bell className="h-5 w-5" />
                    {unreadNotificationsCount > 0 && (
                        <span className="absolute top-1 right-1 h-3.5 w-3.5 bg-red-500 border-2 border-white rounded-full flex items-center justify-center text-[8px] font-medium text-white">
                            {unreadNotificationsCount}
                        </span>
                    )}
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-[380px] p-0 overflow-hidden bg-white border-none shadow-2xl rounded-2xl">

                <div className="max-h-[400px] overflow-y-auto">
                    {recentNotifications.length === 0 ? (
                        <div className="p-8 text-center">
                            <div className="h-12 w-12 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 mx-auto mb-3">
                                <Inbox className="h-6 w-6" />
                            </div>
                            <p className="text-xs font-medium text-slate-500">All caught up!</p>
                        </div>
                    ) : (
                        recentNotifications.map((notification) => (
                            <DropdownMenuItem
                                key={notification._id}
                                className={`p-4 flex items-start gap-4 cursor-pointer focus:bg-slate-50 border-b border-slate-50 last:border-0 ${!notification.isRead ? "bg-blue-50/20" : ""
                                    }`}
                                onClick={() => handleNotificationClick(notification)}
                            >
                                <div className={`mt-0.5 h-8 w-8 rounded-lg flex items-center justify-center shrink-0 ${notification.type === "new_booking"
                                    ? "bg-amber-100 text-amber-600"
                                    : "bg-blue-100 text-blue-600"
                                    }`}>
                                    {notification.type === "new_booking" ? (
                                        <Calendar className="h-4 w-4" />
                                    ) : (
                                        <CheckCircle2 className="h-4 w-4" />
                                    )}
                                </div>
                                <div className="flex-1 space-y-1">
                                    <p className={`text-xs leading-relaxed ${!notification.isRead ? "font-bold text-slate-900" : "font-normal text-slate-900 opacity-60"}`}>
                                        {notification.message}
                                    </p>
                                    <p className="text-[10px] font-medium text-slate-400 uppercase tracking-tighter">
                                        {format(new Date(notification.createdAt), "MMM d, h:mm a")}
                                    </p>
                                </div>
                            </DropdownMenuItem>
                        ))
                    )}
                </div>

                <div className="p-2 bg-slate-50 border-t border-slate-100">
                    <Button
                        variant="ghost"
                        className="w-full text-xs font-bold text-blue-600 hover:text-blue-700 hover:bg-blue-50 py-4 h-auto rounded-xl"
                        onClick={() => setCurrentView("NOTIFICATIONS")}
                    >
                        View All Notifications
                    </Button>
                </div>
            </DropdownMenuContent>
        </DropdownMenu>
    );
}

"use client";

import React from "react";
import { format } from "date-fns";
import {
