                    transition={{ duration: 0.6 }}
                    className="bg-background border border-border/40 shadow-none rounded-xl overflow-hidden"
                >
                    <div className="text-center pb-2 pt-8 px-6 border-b border-border/10">
                        <h1 className="text-2xl font-bold">
                            Book Your Event
                        </h1>
                        <p className="text-muted-foreground text-sm mt-1">
                            Fill in the details below and we&apos;ll confirm your booking.
                        </p>
                    </div>

                    <div className="p-6 space-y-6">
                        {/* Event Type */}
                        <div className="space-y-2">
                            <Label>Event Type *</Label>
                            <Select
                                value={vm.eventType}
                                onValueChange={(v) => { vm.setEventType(v); vm.missingFields.includes("eventType") && vm.setMissingFields(vm.missingFields.filter(f => f !== "eventType")); }}
                                disabled={vm.isDataLoading}
                            >
                                <SelectTrigger className={`w-full bg-muted/20 ${vm.missingFields.includes("eventType") ? "border-red-500/50 ring-red-500/20" : ""}`} data-test-id="select-event-type">
                                    <SelectValue placeholder={vm.isDataLoading ? "Loading events..." : "Choose event type"} />
                                </SelectTrigger>
                                <SelectContent>
                                    {vm.events.map((event) => (
                                        <SelectItem key={event._id} value={event.name}>
                                            {event.name}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>

                        {/* Date & Time */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label>Date *</Label>
                                <Popover>
                                    <PopoverTrigger asChild>
                                        <Button
                                            variant="outline"
                                            className={`w-full justify-start bg-muted/20 ${vm.missingFields.includes("eventDate") ? "border-red-500/50 ring-red-500/20 text-red-500" : ""}`}
                                            data-test-id="btn-pick-date"
                                            disabled={vm.isPreSelected}
                                        >
                                            <CalendarDays className="mr-2 h-4 w-4" />
                                            {vm.eventDate
                                                ? format(vm.eventDate, "PPP")
                                                : "Pick a date"}
                                        </Button>
                                    </PopoverTrigger>
                                    <PopoverContent className="w-auto p-0" align="start">
                                        <Calendar
                                            mode="single"
                                            selected={vm.eventDate}
                                            onSelect={(d) => { vm.setEventDate(d); vm.missingFields.includes("eventDate") && vm.setMissingFields(vm.missingFields.filter(f => f !== "eventDate")); }}
                                            disabled={(date) => date < new Date()}
                                        />
                                    </PopoverContent>
                                </Popover>
                            </div>

                            <div className="space-y-2">
                                <Label>Time *</Label>
                                <Select
                                    value={vm.eventTime}
                                    onValueChange={(v) => { vm.setEventTime(v); vm.missingFields.includes("eventTime") && vm.setMissingFields(vm.missingFields.filter(f => f !== "eventTime")); }}
                                    disabled={vm.isPreSelected}
                                >
                                    <SelectTrigger className={`w-full bg-muted/20 ${vm.missingFields.includes("eventTime") ? "border-red-500/50 ring-red-500/20" : ""}`} data-test-id="select-time">
                                        <Clock className="mr-2 h-4 w-4" />
                                        <SelectValue placeholder="Pick a time" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {TIME_SLOTS.map((t) => (
                                            <SelectItem key={t} value={t}>
                                                {t}
                                            </SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>

                        {/* Client Details */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label>Full Name *</Label>
                                <Input
                                    value={vm.clientName}
                                    onChange={(e) => { vm.setClientName(e.target.value); vm.missingFields.includes("clientName") && vm.setMissingFields(vm.missingFields.filter(f => f !== "clientName")); }}
                                    placeholder="Juan Dela Cruz"
                                    className={`bg-muted/20 ${vm.missingFields.includes("clientName") ? "border-red-500/50 ring-red-500/20" : ""}`}
                                    data-test-id="input-client-name"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Email *</Label>
                                <Input
                                    type="email"
                                    value={vm.clientEmail}
                                    onChange={(e) => { vm.setClientEmail(e.target.value); vm.missingFields.includes("clientEmail") && vm.setMissingFields(vm.missingFields.filter(f => f !== "clientEmail")); }}
                                    placeholder="juan@email.com"
                                    className={`bg-muted/20 ${vm.missingFields.includes("clientEmail") ? "border-red-500/50 ring-red-500/20" : ""}`}
                                    data-test-id="input-client-email"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <Label>Phone *</Label>
                            <Input
                                value={vm.clientPhone}
                                onChange={(e) => { vm.setClientPhone(e.target.value); vm.missingFields.includes("clientPhone") && vm.setMissingFields(vm.missingFields.filter(f => f !== "clientPhone")); }}
                                placeholder="+63 912 345 6789"
                                className={`bg-muted/20 ${vm.missingFields.includes("clientPhone") ? "border-red-500/50 ring-red-500/20" : ""}`}
                                data-test-id="input-client-phone"
                            />
                        </div>

                        {/* Add-ons */}
                        {vm.currentEvent?.addons?.length > 0 && (
                            <div className="space-y-3">
                                <Label>{vm.currentEvent.name} Add-ons</Label>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                    {vm.currentEvent.addons.map((addOn: any) => (
                                        <label
                                            key={addOn.name}
                                            className="flex items-center gap-3 p-3 rounded-lg border border-border/40 bg-muted/5 hover:bg-muted/10 transition-colors cursor-pointer"
                                        >
                                            <Checkbox
                                                checked={vm.addOns.includes(addOn.name)}
                                                onCheckedChange={() => vm.toggleAddOn(addOn.name)}
                                            />
                                            <div className="flex flex-col">
                                                <span className="text-sm font-semibold">{addOn.name}</span>
                                                <span className="text-xs text-muted-foreground">
                                                    +₱{addOn.price.toLocaleString()}
                                                </span>
                                            </div>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Notes */}
                        <div className="space-y-2">
                            <Label>Notes</Label>
                            <Textarea
                                value={vm.notes}
                                onChange={(e) => vm.setNotes(e.target.value)}
                                placeholder="Any special requests or details..."
                                rows={3}
                                className="bg-muted/20"
                                data-test-id="input-notes"
                            />
                        </div>

                        {/* Submit */}
                        <Button
                            onClick={vm.submitBooking}
                            disabled={vm.isSubmitting}
                            className="w-full bg-gradient-to-r from-amber-500 to-orange-500 hover:from-amber-600 hover:to-orange-600 text-white font-semibold py-6"
                            data-test-id="btn-submit-booking"
                        >
                            <Send className="mr-2 h-4 w-4" />
                            {vm.isSubmitting ? "Submitting..." : "Submit Booking"}
                        </Button>

                        {/* Result */}
                        {vm.submitResult && (
                            <motion.div
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                className={`flex items-center gap-2 rounded-lg p-3 text-sm ${vm.submitResult.success
                                    ? "bg-emerald-500/10 text-emerald-600 border border-emerald-500/20"
                                    : "bg-red-500/10 text-red-600 border border-red-500/20"
                                    }`}
                            >
                                {vm.submitResult.success ? (
                                    <CheckCircle className="h-4 w-4" />
                                ) : (
                                    <XCircle className="h-4 w-4" />
                                )}
                                {vm.submitResult.message}
                            </motion.div>
                        )}
                    </div>
                </motion.div>
            </div>
        </div>
    );
}

"use client";

import { useState, useCallback, useEffect } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { useSocket } from "@/lib/hooks/useSocket";
import api from "@/lib/axios";
import type {
  CreateBookingPayload,
  EventType,
} from "@/types/booking";


/**
 * useBooking — ViewModel for the Booking form
 *
 * Handles form state, validation, and submission.
 * Extracts date/time from URL on mount.
 */

export function useBooking() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const { socket, emit } = useSocket();

  // Reference data
  const [events, setEvents] = useState<any[]>([]);
  const [isDataLoading, setIsDataLoading] = useState(true);

  // Form fields
  const [eventType, setEventType] = useState<string>("");
  const [eventDate, setEventDate] = useState<Date | undefined>(undefined);
  const [eventTime, setEventTime] = useState("");
  const [clientName, setClientName] = useState("");
  const [clientEmail, setClientEmail] = useState("");
  const [clientPhone, setClientPhone] = useState("");
  const [notes, setNotes] = useState("");
  const [addOns, setAddOns] = useState<string[]>([]);

  // States
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitResult, setSubmitResult] = useState<{ success: boolean; message: string } | null>(null);
  const [isPreSelected, setIsPreSelected] = useState(false);
  const [missingFields, setMissingFields] = useState<string[]>([]);

  // Fetch active events
  const fetchEvents = useCallback(async () => {
    try {
      const res = await api.get("/api/events");
      const data = Array.isArray(res.data) ? res.data : [];
      setEvents(data);
      setEventType(prev => prev || (data.length > 0 ? data[0].name : ""));
    } catch (error) {
      console.error("Failed to fetch event types:", error);
      setEvents([]);
    } finally {
      setIsDataLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchEvents();
  }, [fetchEvents]);

  useEffect(() => {
    if (!socket) return;
    socket.on("events-updated", fetchEvents);
    return () => {
      socket.off("events-updated", fetchEvents);
    };
  }, [socket, fetchEvents]);

  // Parse URL Params on mount
  useEffect(() => {
    if (!searchParams) return;
    const d = searchParams.get("date");
    const t = searchParams.get("time");

    if (d && t) {
      const parsedDate = new Date(d);
      if (!isNaN(parsedDate.getTime())) {
        setEventDate(parsedDate);
        setEventTime(t);
        setIsPreSelected(true);
      }
    }
  }, [searchParams]);

  const toggleAddOn = useCallback((addOn: string) => {
    setAddOns((prev) =>
      prev.includes(addOn)
        ? prev.filter((a) => a !== addOn)
        : [...prev, addOn]
    );
  }, []);

  const submitBooking = useCallback(async () => {
    // Reset previous missing fields
    setMissingFields([]);
    
    const missing: string[] = [];
    if (!eventType) missing.push("eventType");
    if (!eventDate) missing.push("eventDate");
    if (!eventTime) missing.push("eventTime");
    if (!clientName) missing.push("clientName");
    if (!clientEmail) missing.push("clientEmail");
    if (!clientPhone) missing.push("clientPhone");

    if (missing.length > 0) {
      setMissingFields(missing);
      setSubmitResult({
        success: false,
        message: "Please fill in all required fields.",
      });
      return;
    }

    setIsSubmitting(true);
    setSubmitResult(null);

    try {
      const payload: CreateBookingPayload = {
        eventType: eventType as EventType,
        eventDate: eventDate ? (eventDate as Date).toISOString() : "",
        eventTime,
        clientName,
        clientEmail,
        clientPhone,
        notes,
        addOns,
      };

      const res = await api.post("/api/bookings", payload);

      // Trigger realtime update for admins
      emit("new-booking", res.data.booking);

      setSubmitResult({
        success: true,
        message: "Booking submitted! We'll get back to you shortly.",
      });

      // Redirect home after 3 seconds on success
      setTimeout(() => router.push("/"), 3000);

    } catch (error: unknown) {
      const err = error as { response?: { data?: { error?: string } } };
      setSubmitResult({
        success: false,
        message: err?.response?.data?.error || "Submission failed. Try again.",
      });
    } finally {
      setIsSubmitting(false);
    }
  }, [eventType, eventDate, eventTime, clientName, clientEmail, clientPhone, notes, addOns, emit, router]);

  // Derived: Get current event object
  const currentEvent = events.find(e => e.name === eventType);

  return {
    events,
    isDataLoading,
    currentEvent,
    eventType, setEventType,
    eventDate, setEventDate,
    eventTime, setEventTime,
    clientName, setClientName,
    clientEmail, setClientEmail,
    clientPhone, setClientPhone,
    notes, setNotes,
    addOns, toggleAddOn,
    isSubmitting,
    submitResult,
    submitBooking,
    isPreSelected,
    missingFields, setMissingFields,
  };
}

export default useBooking;

